#include <bits/stdc++.h>
using namespace std;

const int N=3e5+5;

struct Edge{
	int to;
	long long val;
};

bool operator<(Edge x,Edge y){
	return x.val>y.val;
}

int n,m,k;
long long dis[N];
bool b[N];
vector<Edge> g[N];

void Dijkstra(){
	memset(dis,0x3f,sizeof(dis));
	priority_queue<Edge> q;
	dis[1]=0;
	q.push({1,0});
	while(q.size()){
		if(q.size() && b[q.top().to])
			q.pop();
		if(q.empty())
			break;
		int x=q.top().to;
		b[x]=1;
		q.pop();
		for(Edge y:g[x])
			if(dis[y.to]>dis[x]+y.val){
				dis[y.to]=dis[x]+y.val;
				q.push({y.to,dis[y.to]});
			}
	}
}

int main(){
	scanf("%d%d%d",&n,&m,&k);
	for(int i=1,u,v,w;i<=m;i++){
		scanf("%d%d%d",&u,&v,&w);
		for(int j=0;j<=k;j++){
			g[n*j+u].push_back({n*j+v,w});
			g[n*j+v].push_back({n*j+u,w});
			if(j<k){
				g[n*j+u].push_back({n*(j+1)+v,0});
				g[n*j+v].push_back({n*(j+1)+u,0});
			}
		}
	}
	Dijkstra();
	long long ans=1e18;
	for(int i=1;i<=k+1;i++)
		ans=min(ans,dis[n*i]);
	printf("%lld",ans);
	return 0;
}
